example.code:
// Sign up
gtag('event', 'sign_up', { method: 'email' });

// Purchase — transaction_id is REQUIRED for deduplication
gtag('event', 'purchase', {
  transaction_id: 'T12345',
  value: 99.99,
  currency: 'USD',
  items: [{ item_id: 'SKU_001', item_name: 'Premium Plan', price: 99.99, quantity: 1 }]
});
